from itertools import product

def generate_polyominoes(n):
    if n == 1:
        return [np.array([[1]])]

    smaller_polyominoes = generate_polyominoes(n - 1)
    new_polyominoes = []

    for poly in smaller_polyominoes:
        height, width = poly.shape
        # Check all adjacent cells
        for y in range(height):
            for x in range(width):
                if poly[y, x] == 1:
                    for dy, dx in [(-1, 0), (1, 0), (0, -1), (0, 1)]:
                        ny, nx = y + dy, x + dx
                        if 0 <= ny < height and 0 <= nx < width:
                            if poly[ny, nx] == 0:
                                new_poly = np.copy(poly)
                                new_poly[ny, nx] = 1
                                if not is_duplicate(new_poly, new_polyominoes):
                                    new_polyominoes.append(new_poly)
                        else:
                            # Need to expand the array
                            new_poly = np.zeros((height + 2, width + 2), dtype=int)
                            new_poly[1:height+1, 1:width+1] = poly
                            new_ny, new_nx = ny + 1, nx + 1
                            new_poly[new_ny, new_nx] = 1
                            # Trim excess zeros
                            new_poly = trim_polyomino(new_poly)
                            if not is_duplicate(new_poly, new_polyominoes):
                                new_polyominoes.append(new_poly)
    return new_polyominoes

def trim_polyomino(poly):
    non_zero_rows = np.any(poly != 0, axis=1)
    non_zero_cols = np.any(poly != 0, axis=0)
    poly = poly[non_zero_rows][:, non_zero_cols]
    return poly

def is_duplicate(poly, poly_list):
    for p in poly_list:
        if are_equivalent(poly, p):
            return True
    return False

def are_equivalent(p1, p2):
    for _ in range(4):
        if np.array_equal(p1, p2):
            return True
        p1 = np.rot90(p1)
    p1 = np.fliplr(p1)
    for _ in range(4):
        if np.array_equal(p1, p2):
            return True
        p1 = np.rot90(p1)
    return False

