    for n in range(1, max_n + 1):
        polyominoes = generate_polyominoes(n)
        unique_polyominoes = []
        for poly in polyominoes:
            if not is_duplicate(poly, unique_polyominoes):
                unique_polyominoes.append(poly)
        results[n] = {
            'count': len(unique_polyominoes),
            'shapes': unique_polyominoes
        }
    return results

