    if n == 1:
        return [{(0, 0)}]

    smaller_polyominoes = generate_polyominoes(n - 1)
    new_polyominoes = set()

    for poly in smaller_polyominoes:
        for (x, y) in poly:
            for (dx, dy) in [(1, 0), (-1, 0), (0, 1), (0, -1)]:
                new_square = (x + dx, y + dy)
                if new_square not in poly:
                    new_poly = poly | {new_square}
                    normalized = normalize(new_poly)
                    new_poly_tuple = tuple(sorted(normalized))
                    new_polyominoes.add(new_poly_tuple)

    unique_polyominoes = [set(poly) for poly in new_polyominoes]
    return unique_polyominoes

def remove_duplicates(polyominoes):
    unique = []
    seen = set()

    for poly in polyominoes:
        poly_normalized = normalize(list(poly))
        poly_tuple = tuple(sorted(poly_normalized))
        if poly_tuple in seen:
